CREATE TYPE "SyncStatus" AS ENUM ('pending','synced','conflict');
CREATE TABLE "items" ("id" UUID PRIMARY KEY,"model_number" TEXT NOT NULL UNIQUE,"price" DECIMAL(12,2) NOT NULL,"photo_url" TEXT,"size" TEXT,"material" TEXT,"deleted_at" TIMESTAMPTZ,"created_at" TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,"sync_status" "SyncStatus" NOT NULL DEFAULT 'synced');
CREATE TABLE "item_variants" ("id" UUID PRIMARY KEY,"item_id" UUID NOT NULL REFERENCES "items"("id") ON DELETE CASCADE,"color" TEXT NOT NULL,"stock_quantity" INTEGER NOT NULL DEFAULT 0,"deleted_at" TIMESTAMPTZ,"created_at" TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,"sync_status" "SyncStatus" NOT NULL DEFAULT 'synced',UNIQUE("item_id","color"));
CREATE TABLE "sales" ("id" UUID PRIMARY KEY,"total_amount" DECIMAL(12,2) NOT NULL,"deleted_at" TIMESTAMPTZ,"created_at" TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,"sync_status" "SyncStatus" NOT NULL DEFAULT 'synced');
CREATE TABLE "sale_items" ("id" UUID PRIMARY KEY,"sale_id" UUID NOT NULL REFERENCES "sales"("id") ON DELETE CASCADE,"item_variant_id" UUID NOT NULL REFERENCES "item_variants"("id"),"quantity" INTEGER NOT NULL,"unit_price_at_sale" DECIMAL(12,2) NOT NULL,"created_at" TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP,"sync_status" "SyncStatus" NOT NULL DEFAULT 'synced');
CREATE TABLE "admin_user" ("id" UUID PRIMARY KEY,"username" TEXT NOT NULL UNIQUE,"password_hash" TEXT NOT NULL,"refresh_token_hash" TEXT,"created_at" TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "conflict_logs" ("id" UUID PRIMARY KEY,"table_name" TEXT NOT NULL,"record_id" UUID NOT NULL,"client_payload" JSONB NOT NULL,"server_payload" JSONB NOT NULL,"resolution" TEXT NOT NULL,"created_at" TIMESTAMPTZ NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX "items_model_number_idx" ON "items"("model_number");
CREATE INDEX "item_variants_color_idx" ON "item_variants"("color");
CREATE INDEX "sales_created_at_idx" ON "sales"("created_at");
